<?php require __DIR__.'/includes/pawn_bootstrap.php';if(!pawn_permission($conn,'view')&&!pawn_permission($conn,'open'))die('Access denied.');$id=(int)($_GET['id']??0);$st=$conn->prepare('SELECT pe.*,c.customer_name,c.mobile,c.address_line1,c.city,c.state,pc.category_name FROM pawn_entries pe JOIN customers c ON c.id=pe.customer_id JOIN pawn_categories pc ON pc.id=pe.pawn_category_id WHERE pe.id=? AND pe.business_id=? AND pe.branch_id=?');$st->bind_param('iii',$id,$businessId,$branchId);$st->execute();$pawn=$st->get_result()->fetch_assoc();$st->close();if(!$pawn)die('Pawn not found.');$st=$conn->prepare('SELECT pi.*,m.metal_name FROM pawn_items pi JOIN metals m ON m.id=pi.metal_id WHERE pi.pawn_entry_id=? AND pi.business_id=?');$st->bind_param('ii',$id,$businessId);$st->execute();$items=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$st=$conn->prepare('SELECT pp.*,pm.method_name FROM pawn_payments pp LEFT JOIN payment_methods pm ON pm.id=pp.payment_method_id WHERE pp.pawn_entry_id=? AND pp.business_id=? ORDER BY pp.payment_date DESC,pp.id DESC');$st->bind_param('ii',$id,$businessId);$st->execute();$payments=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$st=$conn->prepare('SELECT pi.*,pm.method_name FROM pawn_interest_collections pi LEFT JOIN payment_methods pm ON pm.id=pi.payment_method_id WHERE pi.pawn_entry_id=? AND pi.business_id=? ORDER BY pi.collection_date DESC,pi.id DESC');$st->bind_param('ii',$id,$businessId);$st->execute();$interest=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$theme=pawn_theme($conn,$businessId);$businessName=$_SESSION['business_name']??'Jewellery ERP';?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=pawn_e($pawn['pawn_no'])?></title><?php include 'includes/links.php';include __DIR__.'/includes/pawn_styles.php';?></head><body><?php include 'includes/sidebar.php';?><main class="app-main"><?php include 'includes/nav.php';?><div class="content-wrap"><div class="pawn-card mb-3"><div class="pawn-head"><div><div class="pawn-title"><?=pawn_e($pawn['pawn_no'])?></div><div class="small text-muted"><?=pawn_e($pawn['customer_name'])?> · <?=pawn_e($pawn['mobile'])?></div></div><div class="d-flex gap-2"><a class="btn btn-light btn-sm" href="pawn-list.php">Back</a><?php if(in_array($pawn['status'],['Active','Partially Paid'],true)):?><a class="btn btn-light btn-sm" href="pawn-interest.php?id=<?=$id?>">Collect Interest</a><a class="btn btn-light btn-sm" href="pawn-payment.php?id=<?=$id?>">Payment</a><a class="btn btn-theme" href="pawn-release.php?id=<?=$id?>">Release</a><?php endif?></div></div><div class="section"><div class="row g-3"><div class="col-md-3"><div class="stat"><small>Principal</small><strong>₹<?=pawn_money($pawn['principal_amount'])?></strong></div></div><div class="col-md-3"><div class="stat"><small>Balance</small><strong>₹<?=pawn_money($pawn['balance_principal'])?></strong></div></div><div class="col-md-3"><div class="stat"><small>Interest Collected</small><strong>₹<?=pawn_money($pawn['total_interest_collected'])?></strong></div></div><div class="col-md-3"><div class="stat"><small>Status</small><strong><span class="status s-<?=str_replace(' ','-',$pawn['status'])?>"><?=pawn_e($pawn['status'])?></span></strong></div></div></div></div><div class="section"><div class="section-title">Loan Details</div><div class="row"><div class="col-md-4"><b>Pawn Date:</b> <?=pawn_e($pawn['pawn_date'])?></div><div class="col-md-4"><b>Due Date:</b> <?=pawn_e($pawn['due_date'])?></div><div class="col-md-4"><b>Category:</b> <?=pawn_e($pawn['category_name'])?></div><div class="col-md-4 mt-2"><b>Interest:</b> <?=pawn_e($pawn['interest_percent'])?>% <?=pawn_e($pawn['interest_period'])?></div><div class="col-md-8 mt-2"><b>Address:</b> <?=pawn_e(trim($pawn['address_line1'].' '.$pawn['city'].' '.$pawn['state']))?></div></div></div></div><div class="pawn-card mb-3"><div class="pawn-head"><div class="pawn-title">Pledged Items</div></div><div class="table-responsive"><table class="table mb-0"><tr><th>Metal</th><th>Description</th><th>Qty</th><th>Gross</th><th>Stone</th><th>Net</th><th>Purity</th><th class="text-end">Value</th></tr><?php foreach($items as $x):?><tr><td><?=pawn_e($x['metal_name'])?></td><td><?=pawn_e($x['item_description'])?></td><td><?=pawn_e($x['quantity'])?></td><td><?=pawn_e($x['gross_weight'])?></td><td><?=pawn_e($x['stone_weight'])?></td><td><?=pawn_e($x['net_weight'])?></td><td><?=pawn_e($x['purity'])?></td><td class="text-end">₹<?=pawn_money($x['estimated_value'])?></td></tr><?php endforeach?></table></div></div><div class="row g-3"><div class="col-lg-6"><div class="pawn-card"><div class="pawn-head"><div class="pawn-title">Principal Payments</div></div><div class="table-responsive"><table class="table mb-0"><tr><th>Date</th><th>Receipt</th><th class="text-end">Principal</th><th class="text-end">Total</th></tr><?php foreach($payments as $x):?><tr><td><?=pawn_e($x['payment_date'])?></td><td><?=pawn_e($x['receipt_no'])?></td><td class="text-end">₹<?=pawn_money($x['principal_amount'])?></td><td class="text-end">₹<?=pawn_money($x['total_amount'])?></td></tr><?php endforeach?></table></div></div></div><div class="col-lg-6"><div class="pawn-card"><div class="pawn-head"><div class="pawn-title">Interest Collections</div></div><div class="table-responsive"><table class="table mb-0"><tr><th>Date</th><th>Receipt</th><th>Period</th><th class="text-end">Total</th></tr><?php foreach($interest as $x):?><tr><td><?=pawn_e($x['collection_date'])?></td><td><?=pawn_e($x['receipt_no'])?></td><td><?=pawn_e($x['from_date'].' - '.$x['to_date'])?></td><td class="text-end">₹<?=pawn_money($x['total_amount'])?></td></tr><?php endforeach?></table></div></div></div></div><?php include 'includes/footer.php';?></div></main><?php include 'includes/script.php';?><script src="assets/js/script.js"></script></body></html>
